336	#!/usr/bin/env python3
337	import json
338	import os
339	import sys
340	import time
341	import urllib.error
342	import urllib.parse
343	import urllib.request
344	from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer
345	
346	MATRIX_URL = os.environ.get("HICLAW_MATRIX_URL", "http://hiclaw-controller:6167").rstrip("/")
347	MATRIX_DOMAIN = os.environ.get("HICLAW_MATRIX_DOMAIN", "matrix-local.hiclaw.io:18080")
348	ADMIN_USER = os.environ.get("HICLAW_ADMIN_USER", "admin")
349	ADMIN_PASSWORD = os.environ.get("HICLAW_ADMIN_PASSWORD", "")
350	MANAGER_USER = os.environ.get("HICLAW_MANAGER_USER", "manager")
351	ADMIN_FULL_ID = f"@{ADMIN_USER}:{MATRIX_DOMAIN}"
352	MANAGER_FULL_ID = f"@{MANAGER_USER}:{MATRIX_DOMAIN}"
353	ROOM_PREFIX = "Chat: "
354	
355	def fail(message, code=500):
356	    raise RuntimeError(f"{code}:{message}")
357	
358	def matrix_request(method, path, payload=None, token=None):
359	    url = f"{MATRIX_URL}{path}"
360	    data = None
361	    headers = {"Content-Type": "application/json"}
362	    if token:
363	      headers["Authorization"] = f"Bearer {token}"
364	    if payload is not None:
365	      data = json.dumps(payload).encode("utf-8")
366	    req = urllib.request.Request(url, data=data, headers=headers, method=method)
367	    try:
368	      with urllib.request.urlopen(req, timeout=20) as resp:
369	        raw = resp.read().decode("utf-8")
370	        return resp.status, json.loads(raw) if raw else {}
371	    except urllib.error.HTTPError as exc:
372	      raw = exc.read().decode("utf-8", "ignore")
373	      try:
374	        body = json.loads(raw) if raw else {}
375	      except Exception:
376	        body = {"error": raw or exc.reason}
377	      return exc.code, body
378	
379	def login():
380	    if not ADMIN_PASSWORD:
381	      fail("HICLAW_ADMIN_PASSWORD is not available inside hiclaw-controller")
382	    status, body = matrix_request(
383	      "POST",
384	      "/_matrix/client/v3/login",
385	      {
386	        "type": "m.login.password",
387	        "identifier": {"type": "m.id.user", "user": ADMIN_USER},
388	        "password": ADMIN_PASSWORD,
389	      },
390	    )
391	    token = body.get("access_token")
392	    if status != 200 or not token:
393	      fail(f"admin login failed: {body.get('error', body)}", 502)
394	    return token
395	
396	def create_room(token, title):
397	    safe = " ".join(title.split()).strip()
398	    if not safe:
399	      fail("chat name cannot be empty", 400)
400	    if len(safe) > 80:
401	      safe = safe[:80].rstrip()
402	    room_name = f"{ROOM_PREFIX}{safe}"
403	    status, body = matrix_request(
404	      "POST",
405	      "/_matrix/client/v3/createRoom",
406	      {
407	        "name": room_name,
408	        "topic": f"Separate HiClaw conversation: {safe}",
409	        "invite": [MANAGER_FULL_ID],
410	        "preset": "trusted_private_chat",
411	        "power_level_content_override": {
412	          "users": {
413	            ADMIN_FULL_ID: 100,
414	            MANAGER_FULL_ID: 100
415	          }
416	        }
417	      },
418	      token=token,
419	    )
420	    room_id = body.get("room_id")
421	    if status not in (200, 201) or not room_id:
422	      fail(f"room creation failed: {body.get('error', body)}", 502)
423	
424	    txn = f"new-chat-{int(time.time())}"
425	    msg_status, msg_body = matrix_request(
426	      "PUT",
427	      f"/_matrix/client/v3/rooms/{urllib.parse.quote(room_id, safe='')}/send/m.room.message/{txn}",
428	      {
429	        "msgtype": "m.text",
430	        "body": f'{MANAGER_FULL_ID} This is a separate admin chat named "{safe}". Treat this room as an isolated conversation thread and keep replies in this room.',
431	        "m.mentions": {"user_ids": [MANAGER_FULL_ID]},
432	      },
433	      token=token,
434	    )
435	    if msg_status not in (200, 201) or "event_id" not in msg_body:
436	      fail(f"initial message failed: {msg_body.get('error', msg_body)}", 502)
437	
438	    return {"room_id": room_id, "room_name": room_name, "event_id": msg_body["event_id"]}
439	
440	def issue_login_token():
441	    token = login()
442	    status, body = matrix_request(
443	      "POST",
444	      "/_matrix/client/v1/login/get_token",
445	      {
446	        "auth": {
447	          "type": "m.login.password",
448	          "identifier": {"type": "m.id.user", "user": ADMIN_USER},
449	          "password": ADMIN_PASSWORD,
450	        }
451	      },
452	      token=token,
453	    )
454	    login_token = body.get("login_token")
455	    if status != 200 or not login_token:
456	      fail(f"login token request failed: {body.get('error', body)}", 502)
457	    return {"login_token": login_token, "expires_in_ms": body.get("expires_in_ms", 0)}
458	
459	def issue_session():
460	    """Password login with a fixed device_id so Element reuses the same device
461	    and starts in restore-session mode, skipping the cross-signing verify screen."""
462	    if not ADMIN_PASSWORD:
463	      fail("HICLAW_ADMIN_PASSWORD not set", 500)
464	    DEVICE_ID = "hiclaw_web_auto"
465	    status, body = matrix_request(
466	      "POST",
467	      "/_matrix/client/v3/login",
468	      {
469	        "type": "m.login.password",
470	        "identifier": {"type": "m.id.user", "user": ADMIN_USER},
471	        "password": ADMIN_PASSWORD,
472	        "device_id": DEVICE_ID,
473	        "initial_device_display_name": "HiClaw Browser",
474	      },
475	    )
476	    access_token = body.get("access_token")
477	    if status != 200 or not access_token:
478	      fail(f"session login failed: {body.get('error', body)}", 502)
479	    return {
480	      "access_token": access_token,
481	      "user_id": body.get("user_id", f"@{ADMIN_USER}:{MATRIX_DOMAIN}"),
482	      "device_id": body.get("device_id", DEVICE_ID),
